 1	import * as React from 'react';
 2	
 3	import { URLParam, HistoryManager } from '../../app/History';
 4	import { ToolbarDropdown } from '../Dropdown/ToolbarDropdown';
 5	import { Reporter, Direction } from '../../types/MetricsOptions';
 6	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 7	import { KialiIcon } from '../../config/KialiIcon';
 8	import { kialiStyle } from 'styles/StyleUtils';
 9	import { infoStyle } from 'styles/IconStyle';
10	import { classes } from 'typestyle';
11	
12	interface Props {
13	  direction: Direction;
14	  onChanged: (reproter: Reporter) => void;
15	  reporter: Reporter;
16	}
17	
18	const metricsReporterInfoStyle = kialiStyle({
19	  marginBottom: '0.125rem',
20	  marginRight: '0.25rem',
21	  marginTop: '0'
22	});
23	
24	export class MetricsReporter extends React.Component<Props> {
25	  static ReporterOptions: { [key: string]: string } = {
26	    destination: 'Destination',
27	    source: 'Source',
28	    both: 'Both'
29	  };
30	
31	  static initialReporter = (direction: Direction): Reporter => {
32	    const reporterParam = HistoryManager.getParam(URLParam.REPORTER);
33	
34	    if (reporterParam !== undefined) {
35	      return reporterParam as Reporter;
36	    }
37	
38	    return direction === 'inbound' ? 'destination' : 'source';
39	  };
40	
41	  onReporterChanged = (reporter: string): void => {
42	    HistoryManager.setParam(URLParam.REPORTER, reporter);
43	    const newReporter = reporter as Reporter;
44	    this.props.onChanged(newReporter);
45	  };
46	
47	  reportTooltip = (
48	    <div>
49	      <ul style={{ listStyleType: 'none' }}>
50	        <li>
51	          <div style={{ display: 'inline-block' }}>
52	            Select the reporter for the metrics displayed. Each Istio metric can be reported by the Source (workload
53	            which emitted the request) and by the Destination (workload which received the request). In general, the
54	            timeseries will look exactly the same because Source and Destination report the same data.
55	          </div>
56	        </li>
57	
58	        <li>
59	          <div style={{ display: 'inline-block' }}>There are some exceptions:</div>
60	        </li>
61	
62	        <li>
63	          <ul style={{ listStyleType: 'circle', marginLeft: '20px' }}>
64	            <li>An opened circuit breaker would cause networking failures only reported by the Source</li>
65	            <li>Fault-injected failures only reported by the Source</li>
66	            <li>
67	              Traffic coming from unknown sources (anything that is not under the Istio mesh) would only be reported by
68	              the Destination
69	            </li>
70	          </ul>
71	        </li>
72	      </ul>
73	    </div>
74	  );
75	
76	  render(): React.ReactNode {
77	    return (
78	      <span>
79	        <ToolbarDropdown
80	          id={'metrics_filter_reporter'}
81	          disabled={false}
82	          handleSelect={this.onReporterChanged}
83	          nameDropdown={'Reported from'}
84	          value={this.props.reporter}
85	          label={MetricsReporter.ReporterOptions[this.props.reporter]}
86	          options={MetricsReporter.ReporterOptions}
87	        />
88	
89	        <Tooltip content={<div style={{ textAlign: 'left' }}>{this.reportTooltip}</div>} position={TooltipPosition.top}>
90	          <KialiIcon.Info className={classes(infoStyle, metricsReporterInfoStyle)} />
91	        </Tooltip>
92	      </span>
93	    );
94	  }
95	}

